package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP15LoginAdministradorExitosoPlaywrightTest extends BaseTestPlaywright {    @Test    void loginAdministradorExitoso() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("admin");        page.locator("input[name='password']")                .fill("admin");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        String contenido = page.content();        assertTrue(                contenido.contains("Panel Administrador"),                "El Panel Administrador no se muestra después del inicio de sesión."        );        assertTrue(                contenido.contains("Estadísticas")                        || contenido.contains("Total Pedidos Completados")                        || contenido.contains("Total Ganancias"),                "La sección de estadísticas no se muestra."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP15-login-administrador-exitoso.png"))                        .setFullPage(true)        );    }}